#!/usr/bin/env bash
set -e

# Force use of first GPU to avoid "device index 2" errors on 2-GPU system
export CUDA_VISIBLE_DEVICES=0

# Systematic 3-Baseline Execution Script
# Autogenerated by Antigravity

DATASETS=(
    "har"
    "natops"
    "fingermovements"
    "selfregulationscp1"
    "basicmotions"
    "handmovementdirection"
    "uwavegesturelibrary"
    "epilepsy"
    "atrialfibrillation"
    "pendigits"
    "racketsports"
    "articularywordrecognition"
    "heartbeat"
    "selfregulationscp2"
    "libras"
    "japanesevowels"
    "cricket"
    "handwriting"
    "ering"
    "motorimagery"
    "ethanolconcentration"
)

SEED=1

# Output directories
MINIROCKET_OUT="out/_active/verify_3baseline_minirocket_20260414"
RESNET1D_OUT="out/_active/verify_resnet1d_baseline_smoke_20260414"
TENSOR_SPDNET_OUT="out/_active/verify_tensor_spdnet_fixedsplit_20260414"

mkdir -p "$MINIROCKET_OUT"
mkdir -p "$RESNET1D_OUT"
mkdir -p "$TENSOR_SPDNET_OUT"

echo "=========================================================="
echo "Starting Systematic 3-Baseline Execution"
echo "Datasets: ${#DATASETS[@]}"
echo "Seed: $SEED"
echo "=========================================================="

# 1. MiniRocket Baseline
echo "----------------------------------------------------------"
echo "[1/3] MiniRocket Official Fixed Split"
echo "----------------------------------------------------------"
for ds in "${DATASETS[@]}"; do
    if [ -f "$MINIROCKET_OUT/$ds/seed$SEED/metrics.json" ]; then
        echo "Skipping MiniRocket for $ds (Already complete)"
    else
        echo "Running MiniRocket for $ds..."
        /home/THL/miniconda3/envs/pia/bin/python scripts/raw_baselines/run_raw_minirocket_official_fixedsplit.py \
            --datasets "$ds" \
            --seed "$SEED" \
            --out-root "$MINIROCKET_OUT"
    fi
done

# 2. ResNet1D E0 Baseline
echo "----------------------------------------------------------"
echo "[2/3] ResNet1D E0 Backbone Baseline"
echo "----------------------------------------------------------"
for ds in "${DATASETS[@]}"; do
    if [ -f "$RESNET1D_OUT/e0/smoke_resnet_e0_${ds}_ep1/summary.json" ] || [ -f "$RESNET1D_OUT/e0/stage2_resnet1d_e0_${ds}_seed${SEED}/summary.json" ]; then
        echo "Skipping ResNet1D E0 for $ds (Already complete)"
    else
        echo "Running ResNet1D E0 for $ds..."
        /home/THL/miniconda3/envs/pia/bin/python scripts/hosts/run_resnet1d_local_closed_form_fixedsplit.py \
            --arm e0 \
            --dataset "$ds" \
            --seed "$SEED" \
            --epochs 30 \
            --train-batch-size 32 \
            --test-batch-size 32 \
            --run-tag "stage2_resnet1d_e0_${ds}_seed${SEED}" \
            --out-root "$RESNET1D_OUT"
    fi
done

# 3. Tensor-SPDNet Baseline
echo "----------------------------------------------------------"
echo "[3/3] Tensor-SPDNet (TensorCSPNet) Baseline"
echo "----------------------------------------------------------"
for ds in "${DATASETS[@]}"; do
    if [ -f "$TENSOR_SPDNET_OUT/e0/seed$SEED/summary.json" ] || [ -f "$TENSOR_SPDNET_OUT/e0/seed$SEED/summary_per_seed.csv" ]; then
        echo "Skipping Tensor-SPDNet for $ds (Already complete)"
    else
        echo "Running Tensor-SPDNet for $ds..."
        /home/THL/miniconda3/envs/pia/bin/python scripts/hosts/run_tensor_spdnet_baseline_fixedsplit.py \
            --dataset "$ds" \
            --seed "$SEED" \
            --out-root "$TENSOR_SPDNET_OUT"
    fi
done

echo "=========================================================="
echo "Systematic 3-Baseline Benchmark Completed Successfully!"
echo "=========================================================="
